  ('locality-0a2fc18c-moex-00167', 'locality-0a2fc18c', 'locality-0a2fc18c-moex-111-d3ff7f6b', 'sub-locality-0a2fc18c-02', NULL, 'single_choice', '民國109年的所得稅法規定，單身者標準扣除額為12萬元，每人的免稅額為8萬8千元，而薪 資扣除額為20萬元。個人的淨所得在54萬元以下，課稅5%，在54萬元到121萬元之間課12%， 在121萬元到242萬元之間課20%。如果小張和小李當年度的薪資所得分別為100萬元和140萬 元，分別算出他們適用平均稅率為何？', '["小張為3.3%，小李為3.8%", "小張為3.3%，小李為5.8%", "小張為5.3%，小李為3.8%", "小張為5.3%，小李為5.8%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:17+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "320", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "經建行政"}'::jsonb, NULL),
